/* Saved canvas dimensions for blit in releaseGraphics.
 * Canvas nativeCtx is NOT saved as a global — releaseGraphics receives
 * it as a parameter to avoid dangling pointer if GC runs between
 * bind and release. */
static s32 g_m3g_canvas_w = 0;
static s32 g_m3g_canvas_h = 0;
static uint8_t *g_m3g_pixels = NULL;  /* M3G renders into this buffer */
static s32 g_m3g_pixels_size = 0;

/* 3D supersampling scale factor — shared with MascotCapsule.
 * Set by jvm_bridge_init, exported from jvm_bridge.c. */
extern int g_render_3d_scale;

static s32 n_Graphics3D_bindGraphics(Runtime *runtime, JClass *clazz) {
    (void)clazz;
    LocalVarItem *lv = runtime->localvar;
    s64 aCtx = localvar_getLong(lv, 0);
    s64 aSurfaceHandle = localvar_getLong(lv, 2);
    s32 aWidth = localvar_getInt(lv, 4);
    s32 aHeight = localvar_getInt(lv, 5);
    s32 aClipX = localvar_getInt(lv, 6);
    s32 aClipY = localvar_getInt(lv, 7);
    s32 aClipW = localvar_getInt(lv, 8);
    s32 aClipH = localvar_getInt(lv, 9);
    s32 aDepth = localvar_getInt(lv, 10);
    s32 aHintBits = localvar_getInt(lv, 11);
    s32 aIsProperRenderer = localvar_getInt(lv, 12);
    s64 aNativeCtx = localvar_getLong(lv, 13);  /* long nativeCtx */

    M3GRenderContext ctx = (M3GRenderContext)aCtx;

    /* Save canvas dimensions for releaseGraphics blit.
     * nativeCtx is passed as a parameter to releaseGraphics, not saved here. */
    g_m3g_canvas_w = aWidth;
    g_m3g_canvas_h = aHeight;

    /* Render at scaled resolution for supersampling */
    s32 scale = g_render_3d_scale;
    s32 scaledW = aWidth * scale;
    s32 scaledH = aHeight * scale;

    /* Allocate/reuse pixel buffer at scaled resolution */
    s32 needed = scaledW * scaledH * 4;
    if (!g_m3g_pixels || g_m3g_pixels_size < needed) {
        free(g_m3g_pixels);
        g_m3g_pixels = (uint8_t *)malloc(needed);
        g_m3g_pixels_size = needed;
    }

    /* Copy current Canvas content into M3G pixel buffer.
     * On Android, m3gBindMemoryTarget points directly to the Canvas Bitmap —
     * the memory target always contains the current 2D content.
     * m3gUpdateBackBuffer then copies this content into the PBuffer,
     * preserving 2D UI and preventing the previous frame's 3D content
     * from persisting (which causes the "frame trail" artifact).
     *
     * On iOS we use a separate buffer (g_m3g_pixels), so we must manually
     * copy Canvas pixels here, converting from Canvas BGRA to M3G RGBA.
     * When supersampling, nearest-neighbor upscale the Canvas content. */
    int pixelsCopied = 0;
    if (aNativeCtx) {
        CGContextRef *ctxPtr = (CGContextRef *)(intptr_t)aNativeCtx;
        CGContextRef cgCtx = *ctxPtr;
        if (cgCtx) {
            uint8_t *canvasPixels = (uint8_t *)CGBitmapContextGetData(cgCtx);
            size_t canvasBPR = CGBitmapContextGetBytesPerRow(cgCtx);
            size_t canvasW = CGBitmapContextGetWidth(cgCtx);
            size_t canvasH = CGBitmapContextGetHeight(cgCtx);
            if (canvasPixels) {
                int srcW = aWidth < (int)canvasW ? aWidth : (int)canvasW;
                int srcH = aHeight < (int)canvasH ? aHeight : (int)canvasH;
                for (int y = 0; y < scaledH; y++) {
                    int srcY = y / scale;
                    if (srcY >= srcH) srcY = srcH - 1;
                    uint8_t *srcRow = canvasPixels + srcY * canvasBPR;
                    uint8_t *dstRow = g_m3g_pixels + y * scaledW * 4;
                    for (int x = 0; x < scaledW; x++) {
                        int srcX = x / scale;
                        if (srcX >= srcW) srcX = srcW - 1;
                        uint8_t *src = srcRow + srcX * 4;
                        uint8_t *dst = dstRow + x * 4;
                        /* Canvas: BGRA → M3G: RGBA */
                        dst[0] = src[2]; /* R */
                        dst[1] = src[1]; /* G */
                        dst[2] = src[0]; /* B */
                        dst[3] = src[3]; /* A */
                    }
                }
                pixelsCopied = 1;
            }
        }
    }
    if (!pixelsCopied) {
        memset(g_m3g_pixels, 0, needed);
    }

    if (m3gSetRenderBuffers(ctx, aDepth ?
                            M3G_COLOR_BUFFER_BIT|M3G_DEPTH_BUFFER_BIT :
                            M3G_COLOR_BUFFER_BIT) && m3gSetRenderHints(ctx, aHintBits)) {
        /* Bind at scaled resolution — M3G engine creates PBuffer to match */
        m3gBindMemoryTarget(ctx, g_m3g_pixels, scaledW, scaledH,
                            M3G_RGBA8, scaledW * 4, 0);
        m3gSetClipRect(ctx, aClipX * scale, aClipY * scale,
                        aClipW * scale, aClipH * scale);
        m3gSetViewport(ctx, aClipX * scale, aClipY * scale,
                        aClipW * scale, aClipH * scale);
    }

    push_int(runtime->stack, 0);
    return RUNTIME_STATUS_NORMAL;
}

