static s32 n_Image2D_ctorSizePixels(Runtime *runtime, JClass *clazz) {
    (void)clazz;
    LocalVarItem *lv = runtime->localvar;
    s64 aM3g = localvar_getLong(lv, 0);
    s32 aFormat = localvar_getInt(lv, 2);
    s32 aWidth = localvar_getInt(lv, 3);
    s32 aHeight = localvar_getInt(lv, 4);
    Instance *aImage = (Instance *)localvar_getRefer(lv, 5);

    M3GImageFormat format = (M3GImageFormat)aFormat;

    if (m3g_validateArray(aImage, jsr184BytesPerPixel(format) * aWidth * aHeight))
    {

        M3GImage hImg = m3gCreateImage((M3GInterface)aM3g, format, aWidth, aHeight, 0);
        if (hImg != NULL)
        {
            M3GImageFormat format = (M3GImageFormat)aFormat;

            int bpp = jsr184BytesPerPixel(format);
            jbyte* imageScanline = (jbyte*)malloc(aWidth * bpp);
            for (int i=0; i < aHeight; i++)
            {
                if (aImage) memcpy(imageScanline, (s8*)aImage->arr_body + (aWidth * i * bpp), aWidth * bpp);
                m3gSetSubImage(hImg, 0, i, aWidth, 1, aWidth * bpp, imageScanline);
            }
            m3gCommitImage(hImg);

            free(imageScanline);
        }
        push_long(runtime->stack, (s64)((jlong) hImg));
        return RUNTIME_STATUS_NORMAL;
    }
    push_long(runtime->stack, (s64)(0));
    return RUNTIME_STATUS_NORMAL;
}

