static s32 n_Transform_transformTable(Runtime *runtime, JClass *clazz) {
    (void)clazz;
    LocalVarItem *lv = runtime->localvar;
    Instance *aMatrix = (Instance *)localvar_getRefer(lv, 0);
    Instance *aTableArray = (Instance *)localvar_getRefer(lv, 1);

    // null pointers are never passed
    M3Gfloat * v = aTableArray ? (M3Gfloat *)aTableArray->arr_body : NULL;
    if (v == NULL)
    {
        return RUNTIME_STATUS_NORMAL;
    }
    int tabelArrayLen = (aTableArray ? aTableArray->arr_length : 0);
    M3GMatrix* matrix = aMatrix ? (M3GMatrix *)aMatrix->arr_body : NULL;
    if (matrix == NULL)
    {

        return RUNTIME_STATUS_NORMAL;
    }

    {
        M3Gint i;
        M3GVec4 vec;

        for (i = 0; i < tabelArrayLen; i += 4)
        {
            m3gSetVec4(&vec, v[i + 0], v[i + 1], v[i + 2], v[i + 3]);
            m3gTransformVec4(matrix, &vec);
            v[i + 0] = vec.x;
            v[i + 1] = vec.y;
            v[i + 2] = vec.z;
            v[i + 3] = vec.w;
        }
    }
    return RUNTIME_STATUS_NORMAL;
}

