static s32 n_Transform_mul(Runtime *runtime, JClass *clazz) {
    (void)clazz;
    LocalVarItem *lv = runtime->localvar;
    Instance *aProdArray = (Instance *)localvar_getRefer(lv, 0);
    Instance *aLeftArray = (Instance *)localvar_getRefer(lv, 1);
    Instance *aRightArray = (Instance *)localvar_getRefer(lv, 2);

    if (aRightArray == NULL || aLeftArray == NULL || aProdArray == NULL)
    {
        return RUNTIME_STATUS_NORMAL;
    }

    {
        const M3GMatrix * right = aRightArray ? (const M3GMatrix *)aRightArray->arr_body : NULL;
        if (right == NULL)
        {
            return RUNTIME_STATUS_NORMAL;
        }

        const M3GMatrix * left = aLeftArray ? (const M3GMatrix *)aLeftArray->arr_body : NULL;
        if (left == NULL)
        {

            return RUNTIME_STATUS_NORMAL;
        }

        M3GMatrix * prod = aProdArray ? (M3GMatrix *)aProdArray->arr_body : NULL;
        if (prod == NULL)
        {

            return RUNTIME_STATUS_NORMAL;
        }

        M3GMatrix temp;
        m3gMatrixProduct(&temp, left, right);

        *prod = temp;

    }
    return RUNTIME_STATUS_NORMAL;
}

