void j2me_m3g_reg_natives(MiniJVM *jvm) {
    s32 count = sizeof(m3g_methods) / sizeof(java_native_method);
    native_reg_lib(jvm, m3g_methods, count);
    printf("[M3G] Registered %d native methods\n", count);
}

/* Declared in m3g_egl_ios.m */
extern int eglTerminate(void *dpy);

void j2me_m3g_cleanup(void) {
    /* Destroy all live M3G Interface objects (frees entire scene graph) */
    for (int i = 0; i < g_m3g_interface_count; i++) {
        printf("[M3G] Force-deleting Interface %d\n", i);
        m3gDeleteInterface(g_m3g_interfaces[i]);
    }
    int iface_count = g_m3g_interface_count;
    g_m3g_interface_count = 0;

    /* Free CPU-side pixel buffer */
    if (g_m3g_pixels) {
        free(g_m3g_pixels);
        g_m3g_pixels = NULL;
        g_m3g_pixels_size = 0;
    }
    g_m3g_canvas_w = 0;
    g_m3g_canvas_h = 0;

    /* Terminate EGL (releases EAGL context + all FBO surfaces) */
    eglTerminate(NULL);
    printf("[M3G] Cleanup: %d interfaces, pixel buf, EGL terminated\n", iface_count);
}
